```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PresaleMint {
    address private owner;
    enum State { PresaleLive, SaleLive, SaleClosed }
    State public currentState = State.PresaleLive;

    mapping(address => bool) public presalerList;
    uint256 public presaleAmountMinted;
    uint256 public publicAmountMinted;

    event WhitelistUpdated(address indexed user, bool status);
    event SaleToggled(State newState);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }

    function toggleSale() public onlyOwner {
        if (currentState == State.SaleClosed) {
            revert("Sale is already closed");
        }
        currentState = currentState == State.PresaleLive ? State.SaleLive : State.SaleClosed;
        emit SaleToggled(currentState);
    }

    function whitelist(address user, bool status) public onlyOwner {
        presalerList[user] = status;
        emit WhitelistUpdated(user, status);
    }

    function presaleBuy() public payable {
        require(currentState == State.PresaleLive, "Presale is not live");
        require(presalerList[msg.sender], "User not whitelisted for presale");
        unchecked {
            presaleAmountMinted++;
        }
    }

    function buy() public payable {
        require(currentState == State.SaleLive, "Public sale is not live");
        unchecked {
            publicAmountMinted++;
        }
    }
}
